import{_ as d,o as r,c as e,a0 as a}from"./chunks/framework.AQcSKqPn.js";const c=JSON.parse('{"title":"AI情报日报 2026-07-17","description":"","frontmatter":{"type":"page","title":"AI情报日报 2026-07-17","tags":["ai","daily-report","情报"],"created":"2026-07-17T00:00:00.000Z"},"headers":[],"relativePath":"daily/ai-report-2026-07-17.md","filePath":"daily/ai-report-2026-07-17.md","lastUpdated":1784253727000}'),o={name:"daily/ai-report-2026-07-17.md"};function l(i,t,n,h,s,p){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="ai情报日报-2026-07-17" tabindex="-1">AI情报日报 2026-07-17 <a class="header-anchor" href="#ai情报日报-2026-07-17" aria-label="Permalink to &quot;AI情报日报 2026-07-17&quot;">​</a></h1><h2 id="ai-hot-精选" tabindex="-1">AI HOT 精选 <a class="header-anchor" href="#ai-hot-精选" aria-label="Permalink to &quot;AI HOT 精选&quot;">​</a></h2><h3 id="产品发布-更新" tabindex="-1">产品发布/更新 <a class="header-anchor" href="#产品发布-更新" aria-label="Permalink to &quot;产品发布/更新&quot;">​</a></h3><ol><li><p><strong>Grok 推出 Automations 功能：定时或邮件触发，自动执行任务并汇报结果</strong> xAI 为 Grok 引入 Automations 功能，用户可描述一次任务，让 Grok 按计划（一次/每日/工作日/每周/每月/每年）或邮件触发自动运行。每次执行都是一次完整对话，结果保存至运行历史，支持邮件或应用内通知。 <a href="https://x.ai/news/grok-automations" target="_blank" rel="noreferrer">来源</a></p></li><li><p><strong>ChatGPT 工作区支持文档、表格、幻灯片编辑</strong> 在 ChatGPT 工作区中可直接创建和编辑精美的文档、电子表格和幻灯片，进一步扩展 ChatGPT 的生产力场景。 <a href="https://x.com/ChatGPTapp/status/2077826846373380535" target="_blank" rel="noreferrer">来源</a></p></li><li><p><strong>天工短剧工作台发布&quot;Agent智能分镜+无限画布&quot;双轨创作模式</strong> 昆仑万维推出双轨创作模式，通过导演Agent自动解析剧本、规划站位与机位，解决AI短剧角色变脸和站位漂移问题。已有三部作品上线DramaWave，7天实现百万美元级营收。 <a href="https://mp.weixin.qq.com/s/WlGAeogkF_N5122nHA0TtQ" target="_blank" rel="noreferrer">来源</a></p></li><li><p><strong>MiniMax Code 2.0 桌面端焕新：底层架构全面升级</strong> 基于 Pi Agent 框架重构，显著提升会话启动速度与长程复杂任务稳定性。已与恒生金融数据库、企查查 MCP 打通，金融模块即将上线。 <a href="https://mp.weixin.qq.com/s/mQeBO0xC6Z1R0LqZX5TvNg" target="_blank" rel="noreferrer">来源</a></p></li><li><p><strong>面壁智能开源企业AI数字员工平台 StaffDeck</strong> 面壁智能联合多团队开源 StaffDeck，一个用于构建与管理数字员工的企业平台，将专业知识、SOP 和决策规则转化为持续工作的数字员工。 <a href="https://x.com/OpenBMB/status/2077741814799548451" target="_blank" rel="noreferrer">来源</a></p></li><li><p><strong>Anthropic 发布 Claude Fable 5，可在 Claude Cowork 中自主执行深度任务</strong> Anthropic 发布最强通用模型 Claude Fable 5，专为长时间、多步骤的复杂异步工作设计，可自主执行深度研究、尽职调查等任务。 <a href="https://claude.com/blog/working-with-claude-fable-5-in-claude-cowork" target="_blank" rel="noreferrer">来源</a></p></li></ol><h3 id="行业动态" tabindex="-1">行业动态 <a class="header-anchor" href="#行业动态" aria-label="Permalink to &quot;行业动态&quot;">​</a></h3><ol start="7"><li><p><strong>欧盟裁定 Google 必须向竞争对手开放 Android 和 Search，影响 Gemini 等 AI 服务</strong> 欧盟依据 DMA 裁定 Google 必须向竞争对手开放 Android 和 Google Search 的关键部分，包括允许第三方 AI 助手和搜索引擎获得更大访问权限，可能削弱 Google 对两大核心平台的控制。 <a href="https://www.theverge.com/policy/966438/eu-google-android-ai-interoperability-search-data-dma" target="_blank" rel="noreferrer">来源</a></p></li><li><p><strong>台积电上调2026年资本支出预测至600~640亿美元，A14制程进展顺利</strong> 台积电2026Q2财报说明会上调资本支出预测，董事长魏哲家表示预计2028年量产的A14制程（1.4nm）开发进展顺利，将成为比2nm更大、更持久的工艺节点。 <a href="https://www.ithome.com/0/977/544.htm" target="_blank" rel="noreferrer">来源</a></p></li></ol><h3 id="论文研究" tabindex="-1">论文研究 <a class="header-anchor" href="#论文研究" aria-label="Permalink to &quot;论文研究&quot;">​</a></h3><ol start="9"><li><strong>Moonshot AI 发布 PerceptionBench：多模态模型视觉感知能力诊断基准</strong> 从40多个现有基准中模型实际失败案例归纳出的视觉感知基准，包含10项原子感知能力和3000道验证题。所有测试模型准确率均未超过60%，表明模型更多是猜测而非真正感知。 <a href="https://www.kimi.com/blog/perception-bench" target="_blank" rel="noreferrer">来源</a></li></ol><h3 id="技巧与观点" tabindex="-1">技巧与观点 <a class="header-anchor" href="#技巧与观点" aria-label="Permalink to &quot;技巧与观点&quot;">​</a></h3><ol start="10"><li><strong>Anthropic 用 Claude Code 大规模迁移代码：Bun 百万行 Zig 转 Rust，两周完成</strong> Anthropic 工程师用 Claude Code 在两周内将 Bun 的百万行 Zig 代码迁移至 Rust，100% 现有测试通过。消耗约 16.5 万美元 API 成本，但编译时间从八分钟降至两秒，二进制启动快 6 倍。 <a href="https://claude.com/blog/ai-code-migration" target="_blank" rel="noreferrer">来源</a></li></ol><hr><h2 id="小红书爆款-top-10" tabindex="-1">小红书爆款 TOP 10 <a class="header-anchor" href="#小红书爆款-top-10" aria-label="Permalink to &quot;小红书爆款 TOP 10&quot;">​</a></h2><p>数据日期：2026-07-14（前天） | 按新增互动量排序</p><table tabindex="0"><thead><tr><th>#</th><th>标题</th><th>博主</th><th>新增互动</th><th>点赞</th><th>收藏</th><th>评论</th><th>粉丝</th></tr></thead><tbody><tr><td>1</td><td>小孩的视角那简直就是童年阴影</td><td>思雨的小日子</td><td>16w+</td><td>15w+</td><td>1w+</td><td>408</td><td>346</td></tr><tr><td>2</td><td>不同年龄人休息时发出的声音</td><td>纱纱子</td><td>16w+</td><td>13w+</td><td>2w+</td><td>8,838</td><td>1w+</td></tr><tr><td>3</td><td>经典永流传</td><td>是郭雨妍</td><td>15w+</td><td>13w+</td><td>1w+</td><td>175</td><td>92w+</td></tr><tr><td>4</td><td>(无标题)</td><td>伴我闯天涯</td><td>14w+</td><td>12w+</td><td>5,870</td><td>2w+</td><td>7,611</td></tr><tr><td>5</td><td>(无标题)</td><td>呆呆陪父打怪兽</td><td>14w+</td><td>13w+</td><td>1,660</td><td>7,111</td><td>2w+</td></tr><tr><td>6</td><td>(无标题) - 周大福/茉莉奶白</td><td>讨厌作业</td><td>12w+</td><td>11w+</td><td>1w+</td><td>1,796</td><td>10w+</td></tr><tr><td>7</td><td>医生：就等你问呢</td><td>伤心小年糕</td><td>11w+</td><td>11w+</td><td>3,244</td><td>1,372</td><td>15</td></tr><tr><td>8</td><td>(无标题) - 150斤牛奶做零食</td><td>阿琳和阿媛</td><td>11w+</td><td>9w+</td><td>1w+</td><td>5,355</td><td>38w+</td></tr><tr><td>9</td><td>我的足球天赋belike</td><td>czl</td><td>11w+</td><td>9w+</td><td>1w+</td><td>1,355</td><td>3,511</td></tr><tr><td>10</td><td>(无标题) - 晚自习钢琴</td><td>冲浪少女王翠娥</td><td>11w+</td><td>9w+</td><td>1w+</td><td>273</td><td>6,381</td></tr></tbody></table><p><strong>爆款规律观察：</strong></p><ul><li>🔥 <strong>搞笑/反差类</strong>内容霸榜（童年阴影、休息声音、经典永流传），持续验证&quot;惊奇+共鸣&quot;公式</li><li>📸 <strong>素人爆款频出</strong>：346粉博主产出16w+互动（#1），15粉产出11w+互动（#7），说明算法依然偏好&quot;有趣内容大于粉丝量&quot;</li><li>🎵 <strong>沉浸式/ASMR</strong>趋势：不同年龄休息声、奶制品制作等&quot;解压&quot;内容高互动</li><li>🤝 <strong>情感共鸣</strong>：父爱、陪伴类内容（#5 呆呆陪父打怪兽）讨论度高（7,111评论）</li><li>📈 <strong>视频为主</strong>：TOP 10几乎全是短视频形式</li></ul><hr><p><em>数据来源：AI HOT (<a href="https://aihot.virxact.com" target="_blank" rel="noreferrer">https://aihot.virxact.com</a>) + RedFox 小红书爆款监测</em><em>生成时间：2026-07-17 09:15 BJT</em></p>',18)])])}const w=d(o,[["render",l]]);export{c as __pageData,w as default};
